     1→<template>
     2→  <div class="app-container">
     3→    <AppHeader class="app-header no-print">
     4→      <template #right-actions>
     5→        <div class="export-area no-print">
     6→          <div v-if="showDivergenceWarning" class="divergence-warning">
     7→            ⚠ Some content may have been changed during formatting. Please review carefully before exporting.
     8→          </div>
     9→          <UButton
    10→            size="xs"
    11→            variant="outline"
    12→            icon="i-heroicons-printer"
    13→            :disabled="!formattedXml"
    14→            @click="handlePrint"
    15→          >
    16→            Export PDF
    17→          </UButton>
    18→          <span class="export-hint">Works best in Chrome. In the print dialog, choose 'Save as PDF'.</span>
    19→        </div>
    20→      </template>
    21→    </AppHeader>
    22→
    23→    <!-- Dual-panel layout: Text input (left) and Preview (right) -->
    24→    <div class="dual-panel-layout">
    25→      <!-- Left Panel: Plain text input -->
    26→      <div class="editor-panel no-print">
    27→        <textarea
    28→          v-model="textContent"
    29→          class="text-input"
    30→          :placeholder="placeholder"
    31→          :disabled="isFormatting"
    32→        />
    33→        <div class="action-bar">
    34→          <div class="type-selector">
    35→            <button
    36→              class="type-btn"
    37→              :class="{ 'type-btn--active': selectedDocType === 'resume' }"
    38→              :disabled="isFormatting"
    39→              @click="selectedDocType = 'resume'"
    40→            >
    41→              Resume
    42→            </button>
    43→            <button
    44→              class="type-btn"
    45→              :class="{ 'type-btn--active': selectedDocType === 'letter' }"
    46→              :disabled="isFormatting"
    47→              @click="selectedDocType = 'letter'"
    48→            >
    49→              Letter
    50→            </button>
    51→          </div>
    52→          <div class="action-row">
    53→            <UButton
    54→              :disabled="!textContent.trim() || isFormatting"
    55→              :loading="isFormatting"
    56→              @click="formatDocument"
    57→            >
    58→              {{ isFormatting ? 'Formatting...' : formatButtonLabel }}
    59→            </UButton>
    60→            <p v-if="validationMessage" class="validation-message">
    61→              {{ validationMessage }}
    62→            </p>
    63→          </div>
    64→        </div>
    65→      </div>
    66→
    67→      <!-- Right Panel: Preview -->
    68→      <div class="preview-panel">
    69→        <!-- Skeleton loading state -->
    70→        <div v-if="isFormatting" class="skeleton-wrapper no-print">
    71→          <div class="skeleton skeleton-name" />
    72→          <div class="skeleton skeleton-contact" />
    73→          <div class="skeleton-divider" />
    74→          <div class="skeleton skeleton-line" />
    75→          <div class="skeleton skeleton-line skeleton-line--short" />
    76→          <div class="skeleton skeleton-line" />
    77→          <div class="skeleton-gap" />
    78→          <div class="skeleton skeleton-heading" />
    79→          <div class="skeleton skeleton-line" />
    80→          <div class="skeleton skeleton-line skeleton-line--medium" />
    81→          <div class="skeleton skeleton-line" />
    82→          <div class="skeleton skeleton-line skeleton-line--short" />
    83→          <div class="skeleton-gap" />
    84→          <div class="skeleton skeleton-heading" />
    85→          <div class="skeleton skeleton-line skeleton-line--medium" />
    86→          <div class="skeleton skeleton-line skeleton-line--short" />
    87→        </div>
    88→
    89→        <!-- Error state -->
    90→        <div v-else-if="formatError" class="error-state no-print">
    91→          <p class="error-message">{{ formatError }}</p>
    92→          <UButton variant="outline" @click="formatDocument">
    93→            Try Again
    94→          </UButton>
    95→        </div>
    96→
    97→        <!-- Empty state -->
    98→        <div v-else-if="!formattedXml" class="preview-empty no-print">
    99→          <p>Your formatted document will appear here.</p>
   100→        </div>
   101→
   102→        <!-- Preview + review note -->
   103→        <template v-else>
   104→          <PreviewPanel
   105→            :xml-content="formattedXml"
   106→            :zoom="1"
   107→          />
   108→          <div class="review-note no-print">
   109→            Your content has been formatted but not rewritten. Please review before exporting.
   110→          </div>
   111→        </template>
